SELECT count(*) FROM name, aka_name, cast_info, title, movie_keyword, role_type, keyword, char_name WHERE aka_name.person_id = name.id AND cast_info.person_id = name.id AND cast_info.movie_id = title.id AND movie_keyword.movie_id = title.id AND cast_info.role_id = role_type.id AND movie_keyword.keyword_id = keyword.id AND cast_info.person_role_id = char_name.id;